import{_ as a,o as t,c as o,a2 as p}from"./chunks/framework.Bix3-HpO.js";const d=JSON.parse('{"title":"Page Templates","description":"Spinoko Page Templates","frontmatter":{"title":"Page Templates","description":"Spinoko Page Templates","weight":120,"extra":{"order":120},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/page-templates"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/page-templates"}],["meta",{"property":"og:title","content":"Page Templates"}],["meta",{"property":"og:description","content":"Spinoko Page Templates"}],["meta",{"name":"twitter:title","content":"Page Templates"}],["meta",{"name":"twitter:description","content":"Spinoko Page Templates"}]]},"headers":[],"relativePath":"docs/spinoko/page-templates.md","filePath":"docs/spinoko/page-templates.md"}'),l={name:"docs/spinoko/page-templates.md"};function i(s,e,n,r,m,c){return t(),o("div",null,[...e[0]||(e[0]=[p('<h1 id="page-templates" tabindex="-1">Page Templates <a class="header-anchor" href="#page-templates" aria-label="Permalink to &quot;Page Templates&quot;">​</a></h1><p>You can define different templates for your pages in Spinoko.</p><hr><h2 id="using-page-templates" tabindex="-1">Using Page Templates <a class="header-anchor" href="#using-page-templates" aria-label="Permalink to &quot;Using Page Templates&quot;">​</a></h2><p>There are 3 page templates available for displaying <strong>Pages</strong> in your website.</p><ol><li>Default Template</li><li>Cover Template</li><li>Full Screen Cover Template</li></ol><h3 id="default-template" tabindex="-1">Default Template <a class="header-anchor" href="#default-template" aria-label="Permalink to &quot;Default Template&quot;">​</a></h3><p>Here&#39;s an example of a page using the default template:</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-page-template-default.png" alt="spinoko-page-template-default"></p><h3 id="cover-template" tabindex="-1">Cover Template <a class="header-anchor" href="#cover-template" aria-label="Permalink to &quot;Cover Template&quot;">​</a></h3><p>When you choose &quot;Page Cover&quot; as a template in &quot;Page Summary&quot; section, a new section at the end of the sidebar appears called &quot;Cover Page Template Fields&quot;. Here you can add a subtitle and choose whether to display casinos on the page cover or not.</p><p>With this template chosen, your Featured image will be set as a background image for the cover area and the page title will be displayed on top of that.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-page-cover-template.png" alt="spinoko-page-template-cover-admin"></p><p>Here are a couple of examples of pages using the cover template:</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-page-template-cover.jpeg" alt="spinoko-page-template-cover"></p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-page-template-cover-casinos.jpg" alt="spinoko-page-template-cover-casinos"></p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-page-template-cover-no-image.png" alt="spinoko-page-template-cover-no-image"></p><p>Cover page templates have a couple of options:</p><ul><li>Add a cover background image</li><li>Add a subtitle (a h2 tag right below h1)</li><li>Display 3 column reviews block</li></ul><p>You can use combinations of the above options to generate different page styles.</p><h3 id="full-screen-cover-template" tabindex="-1">Full Screen Cover Template <a class="header-anchor" href="#full-screen-cover-template" aria-label="Permalink to &quot;Full Screen Cover Template&quot;">​</a></h3><p>When you choose &quot;Full Screen Page Cover&quot; as a template in &quot;Page Summary&quot; section, a new section at the bottom of the page appears called &quot;Full Screen Cover Page Template Fields&quot;. Here you can define your desired options for your page.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-full-screen-page-cover-template-fields.png" alt="spinoko-full-screen-page-cover-template-fields"></p><p>Here&#39;s an example of a page using the full screen cover template:</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-full-screen-page-cover-template.png" alt="spinoko-full-screen-page-cover-template"></p>',25)])])}const u=a(l,[["render",i]]);export{d as __pageData,u as default};
